const { withDangerousMod, withXcodeProject } = require("expo/config-plugins");
const fs = require("fs");
const path = require("path");

/**
 * Injects the iOS WidgetKit extension during prebuild. The native dirs are gitignored
 * and regenerated by `expo prebuild`, so the canonical Swift/Info.plist/entitlements
 * live in the tracked `widget/ios/VeloqWidget/` tree. This plugin:
 *   1. copies that tree into ios/VeloqWidget/
 *   2. adds a `VeloqWidget` app-extension target to the Xcode project, wires the Swift
 *      files into its Sources phase, sets the bundle id / Info.plist / entitlements /
 *      deployment target, and depends the app target on it.
 *
 * `addTarget('app_extension', …)` from cordova-node-xcode already creates the product,
 * the embed (Copy Files) phase in the app target, and a default build-config list, so
 * this only fills in the phases, the source files, and the extension-specific settings.
 *
 * The App Group entitlement on both the app and this extension is added by
 * with-app-groups.js. Signing (team, App Group capability) is resolved by Xcode/EAS at
 * build time, the same way the existing iCloud capability is.
 */

const TARGET = "VeloqWidget";

function copyDir(src, dest) {
  fs.mkdirSync(dest, { recursive: true });
  for (const entry of fs.readdirSync(src, { withFileTypes: true })) {
    const from = path.join(src, entry.name);
    const to = path.join(dest, entry.name);
    if (entry.isDirectory()) copyDir(from, to);
    else fs.copyFileSync(from, to);
  }
}

function withWidgetFiles(config) {
  return withDangerousMod(config, [
    "ios",
    (cfg) => {
      const src = path.join(cfg.modRequest.projectRoot, "widget", "ios", TARGET);
      const dest = path.join(cfg.modRequest.platformProjectRoot, TARGET);
      copyDir(src, dest);
      return cfg;
    },
  ]);
}

function withWidgetTarget(config) {
  return withXcodeProject(config, (cfg) => {
    const proj = cfg.modResults;
    if (proj.pbxTargetByName(TARGET)) return cfg; // idempotent

    const appBundleId = cfg.ios?.bundleIdentifier || "com.veloq.app";
    const widgetBundleId = `${appBundleId}.${TARGET}`;
    const version = cfg.version || "1.0.0";
    const buildNumber = cfg.ios?.buildNumber || "1";

    const srcDir = path.join(cfg.modRequest.projectRoot, "widget", "ios", TARGET);
    const swiftFiles = fs.readdirSync(srcDir).filter((f) => f.endsWith(".swift"));

    const target = proj.addTarget(TARGET, "app_extension", TARGET, widgetBundleId);

    proj.addBuildPhase([], "PBXSourcesBuildPhase", "Sources", target.uuid);
    proj.addBuildPhase([], "PBXResourcesBuildPhase", "Resources", target.uuid);
    proj.addBuildPhase([], "PBXFrameworksBuildPhase", "Frameworks", target.uuid);

    const group = proj.addPbxGroup([], TARGET, TARGET);
    const mainGroup = proj.getFirstProject().firstProject.mainGroup;
    proj.addToPbxGroup(group.uuid, mainGroup);

    for (const file of swiftFiles) {
      proj.addSourceFile(file, { target: target.uuid }, group.uuid);
    }

    const configurations = proj.pbxXCBuildConfigurationSection();
    for (const key in configurations) {
      const settings = configurations[key].buildSettings;
      if (!settings || settings.PRODUCT_NAME !== `"${TARGET}"`) continue;
      settings.INFOPLIST_FILE = `"${TARGET}/Info.plist"`;
      settings.CODE_SIGN_ENTITLEMENTS = `"${TARGET}/${TARGET}.entitlements"`;
      settings.CODE_SIGN_STYLE = "Automatic";
      settings.IPHONEOS_DEPLOYMENT_TARGET = '"15.1"';
      settings.SWIFT_VERSION = '"5.9"';
      settings.TARGETED_DEVICE_FAMILY = '"1,2"';
      settings.GENERATE_INFOPLIST_FILE = "NO";
      settings.CURRENT_PROJECT_VERSION = `"${buildNumber}"`;
      settings.MARKETING_VERSION = `"${version}"`;
    }

    proj.addTargetDependency(proj.getFirstTarget().uuid, [target.uuid]);
    return cfg;
  });
}

module.exports = function withIosWidget(config) {
  config = withWidgetFiles(config);
  config = withWidgetTarget(config);
  return config;
};
